def f(s: str) -> int:
    """Return the length of the longest substring of s without repeating characters."""
    start = max_len = 0
    last_seen = {}
    for i, ch in enumerate(s):
        if ch in last_seen and last_seen[ch] >= start:
            start = last_seen[ch] + 1
        last_seen[ch] = i
        max_len = max(max_len, i - start + 1)
    return max_len
